const std = @import("std");

pub fn buildBuffer(allocator: std.mem.Allocator, n: usize) !void {
    const buf = try allocator.alloc(u8, n);
    @memset(buf, 0);
    // buf is never freed, never returned, never stored on a struct.
}

const std = @import("std");

pub fn writeOut(allocator: std.mem.Allocator, n: usize) !void {
    const buf = try allocator.alloc(u8, n);
    defer allocator.free(buf);
    @memset(buf, 0);
}

const std = @import("std");

/// Caller owns the returned slice and must free it with `allocator`.
pub fn build(allocator: std.mem.Allocator, n: usize) ![]u8 {
    const buf = try allocator.alloc(u8, n);
    @memset(buf, 0);
    return buf;
}
